import pygame
import random

# Initialize Pygame
pygame.init()

# Constants
WIDTH, HEIGHT = 800, 600
SNAKE_SIZE = 20
SNAKE_SPEED = 15
FOOD_SIZE = 20

# Colors
BLACK = (0, 0, 0)
GREEN = (0, 255, 0)
RED = (255, 0, 0)

# Set up the display
screen = pygame.display.set_mode((WIDTH, HEIGHT))
pygame.display.set_caption("Hydra Game")

# Snake class
class Snake:
    def __init__(self):
        self.body = [(WIDTH // 2, HEIGHT // 2)]
        self.direction = (0, -SNAKE_SPEED)
        self.grow = False

    def move(self):
        head_x, head_y = self.body[0]
        new_head = (head_x + self.direction[0], head_y + self.direction[1])
        self.body.insert(0, new_head)
        if not self.grow:
            self.body.pop()
        else:
            self.grow = False

    def change_direction(self, direction):
        if (direction[0] * -1, direction[1] * -1) != self.direction:
            self.direction = direction

    def eat(self):
        self.grow = True

    def draw(self):
        for segment in self.body:
            pygame.draw.rect(screen, GREEN, (*segment, SNAKE_SIZE, SNAKE_SIZE))

# Food class
class Food:
    def __init__(self):
        self.position = self.random_position()

    def random_position(self):
        x = random.randint(0, (WIDTH - FOOD_SIZE) // FOOD_SIZE) * FOOD_SIZE
        y = random.randint(0, (HEIGHT - FOOD_SIZE) // FOOD_SIZE) * FOOD_SIZE
        return (x, y)

    def draw(self):
        pygame.draw.rect(screen, RED, (*self.position, FOOD_SIZE, FOOD_SIZE))

# Main game loop
def main():
    clock = pygame.time.Clock()
    snake = Snake()
    food = Food()
    running = True

    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_UP:
                    snake.change_direction((0, -SNAKE_SPEED))
                elif event.key == pygame.K_DOWN:
                    snake.change_direction((0, SNAKE_SPEED))
                elif event.key == pygame.K_LEFT:
                    snake.change_direction((-SNAKE_SPEED, 0))
                elif event.key == pygame.K_RIGHT:
                    snake.change_direction((SNAKE_SPEED, 0))

        snake.move()

        # Check for collision with food
        if snake.body[0] == food.position:
            snake.eat()
            food.position = food.random_position()

        # Check for collision with walls or itself
        head_x, head_y = snake.body[0]
        if (head_x < 0 or head_x >= WIDTH or head_y < 0 or head_y >= HEIGHT or
                snake.body[0] in snake.body[1:]):
            running = False

        # Draw everything
        screen.fill(BLACK)
        snake.draw()
        food.draw()
        pygame.display.flip()
        clock.tick(10)

    pygame.quit()

if __name__ == "__main__":
    main()

